sp_angular_provider.script:
function scmModelProvider() {
    "use strict";
    return {
        restrict: "A",
        scope: true,
        require: "ngModel",
        compile: function ($element, $attr) {
            return function (scope, element, attrs, ngModel) {
                function readValueAttribute() {
                    var newValue = element.attr("value");

                    if (newValue == null) {
                        newValue = "";
                    }

                    return newValue;
                }

                function syncModelFromAttribute() {
                    var newValue = readValueAttribute();

                    if (ngModel.$viewValue !== newValue) {
                        ngModel.$setViewValue(newValue);
                        ngModel.$setTouched();
                    }
                }

                ngModel.$render = function () {
                    var value = ngModel.$viewValue;

                    if (Array.isArray(value)) {
                        value = value.length ? value[0] : "";
                    }

                    if (value == null) {
                        value = "";
                    }

                    element.attr("value", String(value));
                };

                var observer = new MutationObserver(function (mutations) {
                    mutations.forEach(function (mutation) {
                        if (mutation.attributeName === "value") {
                            syncModelFromAttribute();
                        }
                    });
                });

                observer.observe(element[0], {
                    attributes: true,
                    attributeFilter: ["value"],
                });

                scope.$on("$destroy", function () {
                    observer.disconnect();
                });
            };
        },
    };
}
